2577; &#25919;&#24220;&#36039;&#35338;&#20844;&#38283; &#27861;&#35215;&#36039;&#35338; &#26045;&#25919;&#35336;&#30059;&#21450;&#26045;&#25919;&#32318;&#25928; &#26989;&#21209;&#32113;&#35336;&#21450;&#30740;&#31350;&#22577;&#21578; &#38928;&#31639;&#12289;&#27770;&#31639;&#26360;&#12289;&#26371;&#35336;&#26376;&#22577;&#21450;&#26371;&#35336;&#21046;&#24230; &#35036;&#21161;&#26696;&#20214;&#21450;&#30456;&#38364;&#35215;&#23450; &#26360;&#38754;&#20043;&#20844;&#20849;&#24037;&#31243;&#21450;&#25505;&#36092;&#22865;&#32004; &#20986;&#22283;&#22577;&#21578; &#29694;&#20195;&#21270;&#39135;&#21697;&#34277;&#29289;&#22283;&#23478;&#32026;&#23526;&#39511;&#22823;&#63820;&#26280;&#64008;&#25919;&#21450;&#35347;&#63894;&#22823;&#63820;&#33288;&#24314;&#35336;&#30059; &#34892;&#25919;&#25351;&#23566;&#26377;&#38364;&#25991;&#26360; &#29151;&#26989;&#21450;&#38750;&#29151;&#26989;&#22522;&#37329;&#22519;&#34892;&#25104;&#26524; &#26412;&#32626;&#28041;&#21450;&#20840;&#27665;&#21033;&#30410;&#20043;&#20219;&#21209;&#32232;&#32068;&#22996;&#21729;&#21033;&#30410;&#33258;&#25105;&#25581;&#38706;&#33287;&#28041;&#21450;&#39135;&#21697;&#27161;&#28310;&#35330;&#23450;&#20043;&#26371;&#35696;&#32000;&#37636; &#20839;&#37096;&#25511;&#21046; &#36938;&#35498;&#36039;&#35338;&#23560;&#21312; &#21214;&#22522;&#27861;&#20363;&#20551;&#19971;&#20241;&#19968;&#20363;&#22806;&#35215;&#23450;&#23560;&#21312; &#27284;&#26696;&#25033;&#29992; &#20491;&#20154;&#21270;&#26381;&#21209; &#21152;&#20837;&#26371;&#21729; &#20154;&#27665;&#30003;&#35531;&#26696;&#20214; &#34277;&#35657;&#26597;&#35426;&#31995;&#32113; &#26657;&#22290;&#39135;&#26448; &#36786;&#34277;&#27544;&#30041;&#23481;&#35377;&#37327;&#30003;&#35531;&#26696;&#26597;&#35426; 為民服務信箱 English 常見問答 網站導覽 衛生局專區 --> 雙語辭彙 --> English --> 資訊安全策略 著作權聲明 隱私權保護宣告 網站資料開放宣告 --> ::: 業務專區 &#39135;&#21697; &#34277;&#21697; &#37291;&#30274;&#22120;&#26448; &#21270;&#31911;&#21697; &#21312;&#31649;&#29702;&#20013;&#24515; &#31649;&#21046;&#34