1911;&#21697;&#29986;&#21697;&#36039;&#35338;&#27284;&#26696;(&#31684;&#20363;)<&#23273;&#33178;&#27792;&#28020;&#20083;> 回上一頁 &#20844;&#21578;&#36039;&#35338; &#26412;&#32626;&#20844;&#21578; &#26412;&#32626;&#26032;&#32862; &#32173;&#35703;&#20844;&#21578; &#27963;&#21205;&#35338;&#24687; &#38928;&#21578;&#27861;&#35215;&#27839;&#38761;&', '{"source_registry_version":"2026-06-25","authority":"Taiwan Food and Drug Administration","domain":"cosmetics","tags":["pif","guidance","checklist","cosmetics"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-food-nutrition-labeling', 'Regulations on Nutrition Labeling for Prepackaged Food Products', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=1633', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'high', '["food","nutrition-label","prepackaged-food"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-food-nutrition-labeling', 'df3683b4ea6e4e974264c47a98eb8d0e6860bd2c3de7ec1fe14fd7b8b04893dc', '2026-06-25T09:45:50.145Z', true, 81652, 16985, 'data/knowledge/documents/tw-tfda-food-nutrition-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations on Nutrition Labeling for Prepackaged Food Products 【Update Date： 2014-04-15 】 unit：&#39135;&#21697;&#32068; 【Announced Date： 2021-04-27 】 【Amended Date： 2021-04-27 】 Chapter I. General Provisions 1. This regulation is established under the provisions of Item 3 of Article 22 of the Act Governing Food Safety and Sanitation (hereinafter referred to as “this Act”). 2. The terms used in this regulation are defined as follows: 2.1 Trans fats (fatty acids): all the geometrical isomers of monounsaturated and polyunsaturated fatty acids having non-conjugated carbon-carbon double bonds in the trans configuration. 2.2 Carbohydrates: namely saccharides; the sum of carbohydrates. 2.3 Sugars: the sum of all free mono and disaccharides. 2.4 Dietary fibers: lignin and edible carbohydrate polymers with three or more monomeric units, which are not hydrolysed or absorbed by the endogenous enzymes in the small intestine of humans. 2.5 Nutrition claims: any representation which states, suggests or implies that a food product has particular calorie or nutrition properties. 3. The nutrition labeling for a prepackaged food on the market shall provide the following information from top to bottom in tabular form orderly shown at a conspicuous place of the outer package or container of the product. 3.1 Title of the “Nutrition Facts”. 3.2 ○ grams (or milliliters) per one serving (or per serving) and the number of servings contained in each package of the product. 3.3 “Per serving (or per one serving)”, “per 100 grams (or milliliters)” or “per serving (or per one serving)”, “daily percentage reference value”. 3.4 Contents of calories. 3.5 Contents of protein. 3.6 Contents of fats, saturated fats (or saturated fatty acids), and trans fats (or trans fatty acids). 3.7 Contents of carbohydrates and sugar. 3.8 Contents of sodium. 3.9 Conformed to the definition of nutrition claim of Article 2. Contents of other nutrients declared in the “Regulations on Nutrition Claim for Prepackaged Food Products”. Contents of other nutrients labeled voluntarily by the manufacturer. Each or total dietary fiber, each sugar, sugar alcohol labeled voluntarily by the manufacturer can be labeled behind carbohydrates item, and after sugar item. Cholesterol, other fatty acids can be labeled behind fat item, and after trans fats (fatty acids) item. Amino acids can be labeled behind protein item. If the vertical form can’t be fully presented, it can be labeled in horizontal continuous form. If multiple prepackaged food or tastes are commonly used in the same nutrient labeling, it can be combined. Nutrition labeling on surface areas smaller than 100 cm2 can be labeled those nutrition information sequentially in horizontal table form. 4. Caloric and nutritional content labeling for prepackaged foods on the market shall be labeled in Arabic numerals and processed under the following provisions: 4.1 Use “per one serving (or per serving)” and “per 100 grams (or milliliters)” for labeling, and the number of servings contained in each package of the product shall also be specified; or 4.2 Use “per one serving (or per serving)” and the provided “daily percentage of reference value” for labeling, and the number of servings contained in each package of the product shall also be specified. Labels shall also be specified the daily nutrient intake reference value if the daily nutrient intake reference value has been set (exempted from the prepackaged food surface areas smaller than 100 cm2). For products without a set daily nutrient intake reference value, the “*” symbol shall precede the daily percentage reference value line and clearly note “*Reference value not set.” Regarding the formatting of Clauses 1 and 2 in the preceding item shall refer to Appendix 1. Infant foods and shall be labeled according to the format of Clause 1 in the preceding item. Products in the form of tablets and capsules (excluding candy foods) shall be labeled according to the format of Clause 2 in the preceding item. 5. The weight (quantity or volume) per serving of the various packaged food products shall consider every times consumption derived from domestic dietary habits and prepackaged food product type. Food products in the form of tablets and capsules (excluding candy foods) shall be labeled as recommended amount (shall be an integer). 6. Measure units for prepackaged food nutrition labeling shall be labelled the following regulations: 6.1 Solid (semi-solid) shall be expressed in grams (g); liquid shall be expressed in milliliters (mL or ml). 6.2 Caloric value is expressed in kilocalories (Kcal or kcal). 6.3 Proteins, fats, saturated fats (fatty acids), and trans fats (fatty acids), total mono or polyunsaturated fats (fatty acids), carbohydrates, sugars, dietary fibers, and sugar alcohols are expressed in grams (g). 6.4 Sodium, cholesterols, and amino acids are expressed in milligrams (mg). 6.5 Vitamins and minerals units refer to Appendix 1. 6.6 Other nutritional values are expressed using the metric system or their common symbols. If product with nutrition claims requires re-hydration, the nutrition labeling must comply with the content (“per serving, per one serving” or “per 100 milliliters”) after re-hydration. If product without nutrition claims requires re-hydration, the nutrition labeling can be in according to the content before or after re-hydration. The re-hydration method shall be stated clearly shown at the outer package. 7. Daily caloric and other nutrient intake reference values shall be labeled according to Appendix 1. 8. The nutrient contents of energy, protein, fats, carbohydrate, sodium, saturated fats (fatty acids), trans fats (fatty acids) and sugars may be labeled as "0" if it meets the criteria in Appendix 2. 9. Data formatting of prepackaged food nutrition labeling units shall conform to the following regulations: 9.1 Each quantity, serving number, daily percentage reference value, caloric, protein, amino acid, fat, fatty acid, cholesterol, carbohydrate, sugar, sodium, dietary fiber, and other nutrients labeled voluntarily shall be labeled using whole integers or integers with one decimal point. The amount of caloric or nutrients per serving can be labeled using integers with two decimal points when the amount of caloric or nutrients per 100 grams (or milliliters) isn’t meet the criteria of labeling as "0". 9.2 The serving size (weight or capacity) can be labeled using integers with two decimal points when it is too small to present the real value if labeled using integers with one decimal points. 9.3 When an non-assembled prepackaged product with varied weight or its serving number is not divisible, the serving number can be labeled as “ This package contains (about) ○ serving(s)” after data formatting to whole integers. 9.4 Labels for vitamins and minerals shall not exceed three significant figures. 9.5 Data formatting shall refer to the Chinese National Standard CNS2925 “Practices for Designating Significant Places in Specific Limiting Values” or “Round half up” method. 10. The values on the nutritional labels of prepackaged foods must be derived from actual test analysis or calculations, and the range of allowable error shall meet the criteria in Appendix 3. If the characteristics of specific nutrient content of fermented food may change with time, the variation of the nutrients can be annotated. 11. The caloric calculation methods for nutritional labels of prepackaged foods shall conform to the following regulations: 11.1 Protein calories are calculated at 4 Kc', '{"source_registry_version":"2026-06-25","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","nutrition-label","prepackaged-food"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-small-prepackaged-food-labeling', 'Regulations Governing the Labeling of Small Prepackaged Food', 'https://www.fda.gov.tw/eng/lawContent.aspx?cid=16&id=3408', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'medium', '["food","small-package","qr-code","prepackaged-food"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-small-prepackaged-food-labeling', '0bd1312fdc3d1f09af1b2e22c5240cb38bb4ad0837b6eedb1546368bfc9e5988', '2026-06-25T09:45:50.145Z', true, 47344, 3146, 'data/knowledge/documents/tw-tfda-small-prepackaged-food-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations Governing the Labeling of Small Prepackaged Food 【Update Date： 2022-04-22 】 unit：&#39135;&#21697;&#32068; 【Announced Date： 2021-09-01 】 【Amended Date： 2021-09-01 】 Article 1 The Regulations are prescribed in accordance with Article 23 of the Act Governing Food Safety and Sanitation. Article 2 Prepackaged food where the largest surface area is less than 20 cm² and being sold in the market may choose one of the following labeling methods: 1. Only the following items shall be labeled on the outer packaging of the product： (1) product name; (2) expiry date; (3) name and telephone number of the responsible domestic company; (4) country of origin and the country of origin of raw materials designated by the central competent authority in a public announcement; (5) reminder information such as allergens. 2. In addition to the product name and expiry date shall be labeled on the outer packaging of the product, the labeling items according to Article 22 Paragraph1 Subparagraphs 2 to 6 and 8 to 10 of the Act Governing Food Safety and Sanitation, shall be disclosed electronically on the outer packaging of the product by using "QR Code" or other electronic means. The reminder information shall also be accompanied on the top or bottom of the electronic labeling as follows: "Scan here to get product information" or equivalent words. Files Regulations Governing the Labeling of Small Prepackaged Food News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-25","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","small-package","qr-code","prepackaged-food"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('tw-tfda-bulk-food-labeling', 'Regulations on Bulk Food Labeling', 'https://www.fda.gov.tw/ENG/lawContent.aspx?cid=16&id=3398', 'Taiwan Food and Drug Administration', 'TW', 'food_labeling', 'regulation', 'medium', '["food","bulk-food","chinese-label"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-tfda-bulk-food-labeling', '8b1c8f337dccca237a7954b03a015b0335d637b967bbd4fd66b51e9c9e1dc3d0', '2026-06-25T09:45:50.145Z', true, 47885, 3976, 'data/knowledge/documents/tw-tfda-bulk-food-labeling.md', 'Food and Drug Administration, Department of Health Go To Content ::: Home Sitemap Contact us Bilingual Glossary 中文版 Go Hot： food additives, Nutrition label, Medicinal Products Food Drugs Controlled Drugs Medical Devices Cosmetics About Taiwan FDA ::: Guidance, Law & Regulations Food Drugs Controlled Drugs Medical Devices Cosmetics Inspections Compliance & Accreditation Others ::: you are in： Home Guidance, Law &amp; Regulations Food Food Regulations on Bulk Food Labeling 【Update Date： 2022-04-18 】 unit：&#39135;&#21697;&#32068; 【Announced Date： 2020-09-17 】 【Amended Date： 2020-09-17 】 Article 1 These regulations are prescribed in accordance with the provisions of Paragraph 2 of Article 25 of the Act Governing Food Safety and Sanitation. Article 2 This regulation is applicable to the Bulk Food of defined in Article 20 of the Enforcement Rules of the Act Governing Food Safety and Sanitation. Article 3 Food business operators with company registration or business registration, which sell the Bulk Food shall label the product name and the country of origin. Except for foods for baking (roasting) and dealing with ready-to-eat foods on-site. Article 4 Food business operators without company registration or business registration, which sell the following Bulk Food shall label the country of origin of the product: Fresh, chilled, frozen, dehydrated, dried, crushed, ground, simple cutting Peanuts, Red beans, Mung beans, Black beans, Soybeans, Buckwheat, Barley, Quinoa, Sesame, Foxtail millet, Garlic, Shiitake, Tea, Red dates, Wolfberry, Hang Chrysanthemum, Chicken, Pork, Mutton ( lamb and goat meat) and Beef. Article 5 Food business operators sell the Bulk Food products that contain beef, pork and other edible parts of cattle and pig shall label the beef, pork and edible parts of cattle and pig of raw material of the country. The country of origin of beef, pork and other edible partsof cattle and pig shall be the country where the cattles and pigs are slaughtered. The beef and edible parts of cattle mentioned in the above paragraph do not include milk, fat of cattle. Article 6 The Bulk Food labeling as provisioned by these Regulations shall be labelled in Chinese and in the form of cards, mark (label) or notice boards which in turn are either posted, hung, erected (inserted), stuck or utilized in other ways which are clearly visible. The vendors who choose to label the products with the mark (label) shall make sure the front of the remainder is larger than 2 millimeter in length and width. Those who choose to label the products with other means of communication shall make sure the front of the remainder is larger than 2 centimeters in length and width. News About FDA 1 Director General 2 Chronicle of History 3 Mission and Future Perspectives 4 Organization and Functions 5 Contact 6 FDA Logo Product 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspection & Research 7 Science and Research 8 GXP Inspection & Lab Accreditation 9 Inspection Law & Regulations 1 Food 2 Drugs 3 Controlled Drugs 4 Medical Devices 5 Cosmetics 6 Inspections 7 Compliance & Accreditation 8 Others Inspection & Research 1 Science and Research 2 GXP Inspection & Lab Accreditation 3 Inspection Journal of Food and Drug Analysis (JFDA) 1 About the JFDA 2 Call for Paper Flyer 3 The Most Cited Articles in 2024 4 Instructions to Authors 5 Impact Factor 6 Editorial Board 7 Articles & Issues 8 Home page 9 Submit Article Conference & Workshop Bilingual Glossary ::: Security Policy Privacy Policy ADD : No.109, Ln. 130, Sec. 1, Academia Rd., Nangang Dist., Taipei City 115, Taiwan (R.O.C.) MAP TEL : 886-2-2787-8000 Consultation Service Hotline Tel: (02) 2787-8200 (Service hours: Weekdays 8:00 AM – 6:00 PM) National 1919 Food Safety Hotline Tel: 1919 (charges apply – local calls at regular rate; mobile phone NT$3.6/min or NT$0.06/sec) Copyright 2018,Taiwan FDA. All Rights Reserved. Best viewed with 1024x768 pixel or above is recommended.', '{"source_registry_version":"2026-06-25","authority":"Taiwan Food and Drug Administration","domain":"food_labeling","tags":["food","bulk-food","chinese-label"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
