insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('tw-customs-export-origin-packaging', '25e1bf2fd5fd6e2a0e3e15378e40f43f4f81bfbb93fdc3cb68b03bb755680893', '2026-06-25T09:45:50.145Z', true, 66956, 4759, 'data/knowledge/documents/tw-customs-export-origin-packaging.md', 'Exporters Must Label Country of Origin on Inner and Outer Packaging to Avoid Clearance Delays and Penalties-Kaohsiung Customs X message close ::: Skip to main content Sitemap Contact us 中文版 :: Popular search： x About KHC Director Organization & Functions Jurisdiction History of KHC Characteristics Location & Transportation Travelers Must Know Departure Arrival VAT Refund for Foreigners Contact Information Leaflet Import/Export Import Sea / Air Cargo Clearance Export Sea / Air Cargo Declaration International Parcel Clearance Maritime Express Consignments Clearance Radiation Detection Procedure Exchange Rate Tariff Database Search System Laws & Regulations Site Links Anti-corruption Platform Provision of Services Service Counters One- Stop Service Download FAQs Import Sea / Air Cargo Clearance Export Sea / Air Cargo Clearance International Parcel Clearance Maritime Express Consignments Clearance Passengers Home > About KHC > News & Events > Exporters Must Label Country of Origin on Inner an... ::: About KHC Director Organization & Functions Jurisdiction History of KHC Characteristics Location & Transportation ::: X Forward friends 「*」Required field * Sender(Required) * Recipient(Required) * Content of email(Required) * Verification code(Required) Regenerate verification code Exporters Must Label Country of Origin on Inner and Outer Packaging to Avoid Clearance Delays and Penalties Kaohsiung Customs (KHC) stated that there have been recent cases where exporters declared Taiwan-bred aquatic products for export. Although the outer boxes were labeled “MADE IN TAIWAN R.O.C,” the inner packaging bore only foreign company names and foreign place names, omitting the country-of-origin-labeling for Taiwan. Consequently, these exporters were not only ordered to withdraw their cargo, but were also referred to the competent authority, the International Trade Administration (TITA) for administrative action. Exporters are urged to verify origin labeling and comply with Foreign Trade Act in case of difficulties in clearance and legal penalties. KHC further explained that pursuant to Article 17, Subparagraph 2 of the Foreign Trade Act, Article 14 and 15, Paragraph 2 of the Regulations Governing Export of Commodities, and Point 2, Subparagraph 1 of Handling Principles for Export Goods without Compliant Country of Origin Labeling or with False Labeling, exported commodities produced in Taiwan shall not fail to or untruthfully label the source identification or the country of origin as required. In addition to marking the country of origin on the goods, their internal and external packaging, in a conspicuous and durable manner, it is strictly prohibited to include foreign places names, country names, or any other markings that could mislead others to believe the commodities are made in other countries, such as a foreign company’s name, address, telephone number, fax, or website. KHC emphasizes that to maintain the reputation and trade interests of Taiwanese products, all exports must be correctly labeled with their country of origin in accordance with the Foreign Trade Act and the Regulations Governing Export of Commodities. If violations regarding failing to label the country of origin as required or false labeling are detected, Customs will refer the cases to TITA for disposition. Exporters with inquiries concerning labeling requirements are advised to consult with TITA before declaration to ensure smooth clearance and protect their interests. Division: Customs Division Ⅱ Contact: Subsection Head Tsai Tel: 07-8057010 #7103 Issued：Secretariat Release date：2026-03-17 Open About KHC Director Organization & Functions Jurisdiction History of KHC Characteristics Location & Transportation Travelers Must Know Departure Arrival VAT Refund for Foreigners Contact Information Leaflet Import/Export Import Sea / Air Cargo Clearance Export Sea / Air Cargo Declaration International Parcel Clearance Maritime Express Consignments Clearance Radiation Detection Procedure Exchange Rate Tariff Database Search System Laws & Regulations Site Links Anti-corruption Platform Provision of Services Service Counters One- Stop Service Download FAQs Import Sea / Air Cargo Clearance Export Sea / Air Cargo Clearance International Parcel Clearance Maritime Express Consignments Clearance Passengers ::: Privacy Open Information Information Security Address: No.3 Jiesing 1st St., Gushan District, Kaohsiung City 80441, Taiwan, R.O.C. ( Location ) TEL: +886-7-561-3251 FAX：+886-7-551-4958 E-mail: khcustoms@customs.gov.tw Office Hours：AM 08:30 to 12:30 ; PM 01:00 to PM 05:00 Monday ~ Friday(kh2) Service Counter：AM 08:30 to PM 05:00 Non-Stop Service Through The Lunch Hou Best viewed at 1024 x 768 resolution . Last updated:2026-06-12', '{"source_registry_version":"2026-06-25","authority":"Taiwan Customs Administration","domain":"customs","tags":["customs","export","origin","packaging"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
