insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('global-wco-harmonized-system', '836f5036a4b1e89616a1fbf607abd4ae2b7e4c8a34c2b77cab4fda264166c848', '2026-06-25T09:45:50.145Z', true, 45409, 8434, 'data/knowledge/documents/global-wco-harmonized-system.md', 'World Customs Organization Navigation English : English French : fran&#231;ais Meta Navigation Sitemap | Contact us | FAQ Search Main Navigation World Customs Organization About Us WCO in brief Discover the WCO Strategic Plan and Goals Annual Reports Vision, Mission and Values Customs Environment Scan Secretary General WCO Members Membership WCO Regional Bodies Regional Intelligence Liaison Offices Regional Training Centres Regional Offices for Capacity Building WCO Structure WCO Secretariat WCO Working Bodies Legal instruments Conventions and Agreements Recommendations Declarations Policies Resolutions WCO standard terms and conditions - Council Decision n° 331 WCO Partners Partner Organizations Memoranda of Understanding Publications International Customs Day International Customs Day 2026 Previous editions Photo Competition Vacancies Calls for tenders Market Consultation Public information on WCO procurement activity Media Newsroom 2026 2025 2024 2023 2022 2021 2020 2019 2018 2017 2016 2015 2014 2013 2012 2011 2010 2009 WCO News Magazine All editions Subscriptions Advertisements Newsletters Newsletter N°1 - 2026 Newsletter N°2 - 2026 Newsletter N°3 - 2026 Newsletter N°4 - 2026 Information for journalists, businesses, individuals and travellers Online Services ACE Experts Portal The Portal is a web-based platform that facilitates the WCO management & mobilization of experts from a global perspective, putting at its centre the actual expert, who can use the new platform to manage their own expert profile. BACUDA The BACUDA project aims at raising awareness and at building capacity in Data Analytics among WCO Members. Bookshop Order WCO’s publications and subscriptions to our services CEN The Customs Enforcement Network Data Model App Help users in navigating through the WCO DM classes, data elements, and information models in interactive mode e-learning The WCO e-learning offer to upskill Customs professionals as well as private sector and academia. Performance Measurement Mechanism Smart Customs Community Portal A hub for WCO Members to explore, discuss, and foster the adoption of disruptive technologies in Customs. WCO Risk Management Compendium WCO Trade Tools International Standards for Customs in one place: HS, Origin and Valuation Topics Index of topics, instruments and tools Communication Nomenclature and Classification of Goods Overview News Activities and Programmes Instruments and Tools Resources Valuation Overview News Activities and Programmes Instruments and Tools Resources Partners Origin Overview News Activities and Programmes Instruments and Tools Resources Partners Enforcement and Compliance Overview News Activities and Programmes Instruments and Tools Resources Partners Procedures and Facilitation Overview News Activities and Programmes Instruments and Tools Resources Partners Capacity Building Overview News Activities and Programmes Instruments and Tools Resources Integrity WCO A-CIP Programme Instruments and Tools News Research Overview Research Paper Series Data Analytics Customs and Environmental Policies News Events Programmes and Projects Research paper Resources E-learning courses Key Issues Revenue Package Economic Competitiveness Package Compliance & Enforcement Package Organizational Development Package Customs in support of Sustainable Development Private Sector Consultative Group Customs Laboratories WCO implementing the WTO TFA Message from Secretary General WTO Trade Facilitation Agreement Implementation Guidance for Section I Mercator Programme WTO and other international organizations History Events Upcoming events Public Webinar on the 30th Anniversary of the WCO Data Model 7th World Customs Organization Global Canine Forum Webinar series on the theme of “Customs Protecting Society through Vigilance and Commitment.” Event history 2026 2025 2024 2023 2022 2021 2020 2019 2018 2017 2016 2015 2014 2013 2012 2011 WCO Area Map and Accommodation Sign In User Name Password Remember me next time Request registration Change Password Reset Password Contact Us Current Location You are here: World Customs Organization Topics Nomenclature and Classification of Goods Overview What is the Harmonized System (HS)? Sidebar Menu Index of topics, instruments and tools Communication Nomenclature and Classification of Goods Overview What is the Harmonized System (HS)? The HS: a Multi-Purpose Tool Frequently asked questions List of Contracting Parties to the HS Convention and countries using the HS Position of Contracting Parties to the HS and non-Contracting Party Administrations News Activities and Programmes Instruments and Tools Resources Valuation Origin Enforcement and Compliance Procedures and Facilitation Capacity Building Integrity Research Customs and Environmental Policies Key Issues WCO implementing the WTO TFA What is the Harmonized System (HS)? New training opportunity for the private sector More information The Harmonized Commodity Description and Coding System generally referred to as "Harmonized System" or simply "HS" is a multipurpose international product nomenclature developed by the World Customs Organization (WCO). It comprises more than 5,000 commodity groups; each identified by a six digit code, arranged in a legal and logical structure and is supported by well-defined rules to achieve uniform classification. The system is used by more than 200 countries and economies as a basis for their Customs tariffs and for the collection of international trade statistics. Over 98 % of the merchandise in international trade is classified in terms of the HS. The HS contributes to the harmonization of Customs and trade procedures, and the non-documentary trade data interchange in connection with such procedures, thus reducing the costs related to international trade. It is also extensively used by governments, international organizations and the private sector for many other purposes such as internal taxes, trade policies, monitoring of controlled goods, rules of origin, freight tariffs, transport statistics, price monitoring, quota controls, compilation of national accounts, and economic research and analysis. The HS is thus a universal economic language and code for goods, and an indispensable tool for international trade. The Harmonized System is governed by "The International Convention on the Harmonized Commodity Description and Coding System". The official interpretation of the HS is given in the Explanatory Notes (5 volumes in English and French) published by the WCO. The Explanatory Notes are also available online subscription, as part of the HS Database ( WCO Trade Tools ) which groups all the available HS Tools, including the information on the HS Nomenclature, the Compendium of Classification Opinions, the Explanatory Notes, the Alphabetical Index and the Brochure on Classification Decisions taken by the Harmonized System Committee. The maintenance of the HS is a WCO priority. This activity includes measures to secure uniform interpretation of the HS and its periodic updating in light of developments in technology and changes in trade patterns. The WCO manages this process through the Harmonized System Committee (representing the Contracting Parties to the HS Convention), which examines policy matters, takes decisions on classification questions, settles disputes and prepares amendments to the Explanatory Notes. The HS Committee also prepares amendments updating the HS every 5 &ndash; 6 years. Decisions concerning the interpretation and application of the Harmonized System, such as classification decisions and amendments to the Explanatory Notes or to the Compendium of Classification Opinions, become effective two months after the approval by the HS Committee. These are reflected in the amending supplements of the relevant WCO Publications also available on WCOTradeTools.org . Current Location You are here: World Customs Organization Topics Nomenclature and Classification of Goods Overview What is the Harmonized Sys', '{"source_registry_version":"2026-06-25","authority":"World Customs Organization","domain":"terminology","tags":["hs-code","customs","classification"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
