insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('global-codex-nutrition-labeling', '888c073dc098619aa640e4c2eca04a560b27cecf9e4ea6a32eebd340b1fcfdee', '2026-06-25T09:45:50.145Z', true, 382281, 19955, 'data/knowledge/documents/global-codex-nutrition-labeling.md', 'Nutrition and Labelling &#124; CODEXALIMENTARIUS FAO-WHO العربية 中文 english français Русский Español AR ZH EN FR RU ES --> --> --> About Codex About Codex Codex60 Members Observers History Science Trade FAO/WHO Codex Trust Fund Consumers Codex Secretariat FAQs Codex Texts Codex Texts Standards Guidelines Codes of Practice Maximum Residue Limits Miscellaneous Codex online databases Codex online databases Pesticide Database Veterinary Drugs Database Food Additives DB (GSFA Online) Themes Themes COVID-19 Animal Feed Antimicrobial Resistance Biotechnology Contaminants Nutrition and Labelling Pesticides Committees Committees Commission (CAC) About Meetings New Work Proposals Elected Officers Executive Committee About Composition & Roles History Meetings Elections and Appointments Codex Regions Codex Regions Africa Asia Europe Latin America and the Caribbean Near East North America and South West Pacific General Subject Committees Commodity Committees Electronic Working Groups Task Forces Meetings Meetings Calendar Information for Delegates Co-hosting meetings Co-hosting meetings Archives Resources Information Documents Circular letters OCS Monitoring Codex elearning course Communications Multimedia Video Podcast Publications News and Events Login Page tools codexalimentarius > Themes > Nutrition and Labelling Nutrition and Labelling With advancements in technology, it is possible today to produce food that caters to innumerable preferences and expectations. Confronted by so many options, consumers nowadays are often faced with the challenge of understanding exactly what they are buying and consuming. Food information, such as nutrients and ingredients, are more important than ever before in helping consumers make informed choices when buying food. The role of Codex in Nutrition and Labelling Codex provides guidance on the compositional requirements of foods so that they are nutritionally safe. Codex also provides guidance on general labelling of foods and the health or nutrient claims producers make on labels, with terms such as "low fat", "high fat" etc. Codex guidance ensures that consumers understand what they are buying and that "it is what it says it is". The Codex Committee on Nutrition and Foods for Special Dietary uses (CCNFSDU) addresses a wide range of technical and regulatory issues for foods that can contribute to the prevention of nutritional deficiencies and diet-related non-communicable diseases. The Codex Committee on Food Labelling (CCFL) sets standards and guidelines for nutrition information on food packages enabling consumers to make informed food choices. As fora in which member countries, leading industry associations and consumer organisations actively participate, the Nutrition and Labelling committees are important tools for influencing the food system and gaining global consensus on nutrition topics. Related Codex Texts Reference Title Committee Last modified EN FR ES AR ZH RU CXS 107-1981 General Standard for the Labelling of Food Additives when sold as such CCFA 2016 CXS 150-1985 Standard for Food Grade Salt CCFA 2025 CXS 106-1983 General Standard for Irradiated Foods CCFH 2003 CXS 1-1985 General Standard for the Labelling of Pre-packaged Foods CCFL 2024 CXG 2-1985 Guidelines on Nutrition Labelling CCFL 2024 CXA 4-1989 Classification of Foods and Animal Feeds CCPR 2025 CXS 151-1985 Standard for Gari CCCPL 2023 CXS 152-1985 Standard for Wheat Flour CCCPL 2023 CXS 153-1985 Standard for Maize (Corn) CCCPL 2019 CXS 155-1985 Standard for Degermed Maize (Corn) Meal and Maize (Corn) Grits CCCPL 2023 CXS 169-1989 Standard for Whole and Decorticated Pea