insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('global-wassenaar-control-lists', '697b142f4a0ceabfa21bf3fb577b1009a46e4ab5ec40a4236156a22a335101cd', '2026-06-25T09:45:50.145Z', true, 65144, 2191, 'data/knowledge/documents/global-wassenaar-control-lists.md', 'Control lists - The Wassenaar Arrangement You are using an outdated browser. Please upgrade your browser to improve your experience. English Français Deutsch Русский Español WA The Wassenaar Arrangement On Export Controls for Conventional Arms and Dual-Use Goods and Technologies Menu WA Home About Us About Us Overview How The WA Works Origins Founding Documents FAQ Employment National Contacts Control Lists Best Practices Other Documents Outreach Related Links Control lists CURRENT CONTROL LISTS (*) Public Documents, Vol II – List of Dual-Use Goods and Technologies and Munitions List Summary of Changes Corr. WA-LIST (25) 1 Corr. (pdf format) WA-LIST (25) 1 Corr. (Word/Zip format) * These Lists reflect the agreements recorded in Appendix 5 to the Initial Elements, dated 19 December 1995, and all subsequent amendments, including those agreed by the 2025 Plenary in December 2025. Implementation date and entry into effect may vary in each Participating State. Please consult the respective National Contacts. SELECTION CRITERIA Criteria for the Selection of Dual-Use Goods, including Sensitive and Very Sensitive Items CONTROL LISTS FROM PREVIOUS YEARS See all Control Lists from previous years Related Documents STAND-ALONE MUNITIONS LIST Stand-Alone Munitions List Corr. (pdf format) The Wassenaar Arrangement’s Munitions List is published here separately for the specific purpose of informing and assisting non-WA countries which are developing or strengthening their national export control list for conventional arms. For the complete and authoritative texts of the WA Lists, please see the current Control Lists above. Search Recent Activities Head of Secretariat Addresses the Asian Export Control Seminar Enhanced Technical Briefing for WA Outreach Partners Introductory Video Wassenaar, The Hague Wittenburg Castle – where agreement was reached in December 1995 to establish the Wassenaar Arrangement Vienna, Austria Vienna - where the Wassenaar Arrangement holds its regular meetings and the Secretariat is located Disclaimer Sitemap Contact us LinkedIn Last updated Last updated: 17 Jun. 2025 Contacts mobile Contact WA SECRETARIAT Vienna, Austria Contact us Back to top', '{"source_registry_version":"2026-06-25","authority":"Wassenaar Arrangement","domain":"export_control","tags":["dual-use","export-control","sensitive-technology"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
