insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('us-fda-cosmetic-labeling-guide', 'FDA Cosmetics Labeling Guide', 'https://www.fda.gov/cosmetics/cosmetics-labeling-regulations/cosmetics-labeling-guide', 'U.S. Food and Drug Administration', 'US', 'cosmetics', 'guidance', 'high', '["cosmetics","labeling-guide","ingredient-declaration"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('us-fda-cosmetic-labeling-guide', 'eb14ffc029f59919451a5b029789312716ee3616b9f0d8389c7dcd4adf54cebf', '2026-06-25T09:45:50.145Z', true, 132380, 79667, 'data/knowledge/documents/us-fda-cosmetic-labeling-guide.md', 'Cosmetics Labeling Guide | FDA Skip to main content Skip to FDA Search Skip to in this section menu Skip to footer links An official website of the United States government Here’s how you know The .gov means it’s official. Federal government websites often end in .gov or .mil. Before sharing sensitive information, make sure you''re on a federal government site. The site is secure. The https:// ensures that you are connecting to the official website and that any information you provide is encrypted and transmitted securely. Search Menu Search FDA Submit search Featured Report a Product Problem Contact FDA FDA Guidance Documents Recalls, Market Withdrawals and Safety Alerts Press Announcements Warning Letters Advisory Committees En Espa&#241ol Products Food Drugs Medical Devices Radiation-Emitting Products Vaccines, Blood, and Biologics Animal and Veterinary Cosmetics Tobacco Products Topics About FDA Combination Products Regulatory Information Safety Emergency Preparedness International Programs News and Events Training and Continuing Education Inspections and Compliance Science and Research Information For Consumers Patients Industry Health Professionals Federal, State and Local Officials Home Cosmetics Cosmetics Labeling Cosmetics Labeling Regulations Cosmetics Labeling Guide Cosmetics Labeling Regulations In this section Cosmetics Labeling Regulations Summary of Cosmetics Labeling Requirements Code of Federal Regulations Sections for Cosmetics Labeling (CFR Title 21, Part 701) Cosmetics Labeling Guide Required Warning Statement for Tanning Products Without Sunscreen Cosmetics Labeling Guide Cosmetics Labeling Regulations Summary of Cosmetics Labeling Requirements Code of Federal Regulations Sections for Cosmetics Labeling (CFR Title 21, Part 701) Cosmetics Labeling Guide Required Warning Statement for Tanning Products Without Sunscreen Available in PDF (316KB) The Cosmetics Labeling Guide provides step-by-step help with cosmetic labeling, with examples and answers to questions manufacturers often ask about labeling requirements under U.S. laws and related regulations. On this page: Laws Regulating Cosmetic Labeling Legal Definitions of Terms Principal Display Panel Placement of Information on Labels Prominence and Conspicuousness Language Type Size Identity Labeling Name and Place of Business Net Quantity of Contents Declaration Warning Statements Ingredient Labeling Prominence Ingredient Identification Order of Declaration Fragrances and Flavors Trade Secret Ingredients Petitioning for Trade Secrecy Drug Ingredients Color Additives Added for Color Matching Incidental Ingredients Dissimilar Product Assortments Similar Product Assortments Branded Shade Lines Direct Mail Cosmetics Off-Package Ingredient Labeling Federal Food, Drug, and Cosmetic Act of 1938, as amended To protect consumers from unsafe or deceptively labeled or packaged products by prohibiting the movement in interstate commerce of adulterated or misbranded food, drugs, devices, and cosmetics. 21 U.S.C. 321-392 The cosmetics marketed in the United States, whether they are manufactured here or are imported from abroad, must comply with the labeling requirements of the Federal Food, Drug, and Cosmetic (FD&C) Act, the Fair Packaging and Labeling (FP&L) Act, and the regulations published by the Food and Drug Administration under the Authority of these two laws. The FD&C Act was enacted by Congress to protect consumers from unsafe or deceptively labeled or packaged products by prohibiting the movement in interstate commerce of adulterated or misbranded food, drug devices and cosmetics. back to top Fair Packaging and Labeling Act To ensure that packages and their labels provide consumers with accurate information about the quantity of contents and facilitate value comparisons. 15 U.S.C. 1451-1460 The FP&L Act was passed by Congress to ensure that packages and their labels provide consumers with accurate information about the quantity of contents and facilitate value comparisons. Federal Food, Drug, and Cosmetic Act The FD&C Act prohibits the marketing of cosmetics that are adulterated or misbranded as well as their adulteration or misbranding while in interstate commerce. Sec. 301, FD&C Act The FD&C Act prohibits the marketing of cosmetics that are adulterated or misbranded as well as their adulteration or misbranding while in interstate commerce. A cosmetic is considered misbranded if..... labeling is false or misleading label does not state the name and address of the manufacturer, packer, or distributor the net quantity of contents the required information is not stated prominently, with conspicuousness and in terms that it is read and understood by consumers under customary conditions of purchase and use the container or its fill is misleading Sec. 602, FD&C Act Sec. 602 of the FD&C Act defines the conditions which cause a cosmetic to be deemed misbranded. Factors Determining Whether Labeling Is Misleading Representations made or suggested Failure to reveal material facts: Material in light of such representations Material with respect to consequences resulting from the intended use Sec. 201(n), FD&C Act 21 CFR 1.21 Labeling may be considered misleading not only because a label statement is deceptive but also because a material fact is not revealed on a label. A fact may be material in light of a statement made on a label or because certain consequences may result from the recommended use of a product. What is a cosmetic? A cosmetic is a product, except soap, intended to be applied to the human body for cleansing, beautifying, promoting attractiveness, or altering the appearance. Sec. 201(i) FD&C Act As defined in section 201(i) of the FD&C Act, a cosmetic is a product, except soap, intended to be applied to the human body for cleansing, beautifying, promoting attractiveness or altering the appearance. In short, one may say that a cosmetic is a product intended to exert a physical, and not a physiological, effect on the human body. The raw materials used as ingredients of cosmetic products are by law also cosmetics. In section 701.20 of Title 21 of the Code of Federal Regulations [21 CFR 701.20], the Food and Drug Administration (FDA) defines the term "soap" as a product in which the non-volatile portion consists principally of an alkali salt of fatty acids, i.e., the traditional composition of soap; the product is labeled as soap; and the label statements refer only to cleansing. If cosmetic claims, e.g., moisturizing, deodorizing, skin softening etc., are made on a label, the product is a cosmetic. Synthetic detergent bars are also considered cosmetics, although they may be labeled as "soap." back to top "Intended use" within the meaning of the FD&C Act is determined from its label or labeling. Senate Report No. 493 73d Cong. 2d Sess. (1934) U.S. Courts of Appeals Decisions According to Senate Report No. 493 and court decisions, the term "intended" in the legal definition of the term "cosmetic" or in other definitions means, with respect to the use of a product, its directed or prescribed use as determined from the statements made on a product''s label or labeling. The courts, in deciding whether a product is a "cosmetic", a "drug", or both a "drug" and a "cosmetic", have relied principally on the consumer''s perception of the meaning of a label statement and less so on the interpretation of the meaning of a label statement by the labeler or a regulatory agency. When is a cosmetic also a drug? A cosmetic is also a drug when it is intended to cleanse, beautify or promote attractiveness as well as treat or prevent disease or otherwise affect the structure or any function of the human body. Sec. 201(g) and (i), FD&C Act Sec. 509, FD&C Act A cosmetic is legally also a drug if it is intended to exert a physical as well as a physiological effect because the FD&C Act defines in section 201(g) the term "drug" to mean, among other things, "articles intended for use in the ... cure, mitigation, t', '{"source_registry_version":"2026-06-25","authority":"U.S. Food and Drug Administration","domain":"cosmetics","tags":["cosmetics","labeling-guide","ingredient-declaration"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
