insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('cn-nmpa-cosmetics-hub', '86e2575036b289c2136d609fa12c1de92cbe22a6328183413739d23cf2ea3647', '2026-06-25T09:45:50.145Z', true, 15996, 4215, 'data/knowledge/documents/cn-nmpa-cosmetics-hub.md', 'Cosmetics 中文 | Contact Us | search search nav Home + About NMPA + Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News + Drugs + Medical Devices + Cosmetics + Resources + Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Home > Cosmetics Requirements for the Pilot Program of Electronic Labels for Cosmetics 2025-12-24 To regulate the pilot program for electronic labels for cosmetics (including toothpaste, hereinafter referred to as "cosmetics"), these Requirements are formulated in accordance with the provisions of the Regulations on Supervision and Administration of Cosmetics (hereinafter referred to as the "Regulations"), the Provisions for Registration and Filing of Cosmetics, the Provisions for Supervision and Administration of Manufacturing and Marketing of Cosmetics, the Provisions for Toothpaste Regulation, and the Measures for the Administration of Cosmetics Labels. NMPA Announcement on Issuing the Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development 2025-12-22 The release of the Opinions is an important measure by the NMPA to implement the strategic deployment of the Party Central Committee and the State Council on comprehensive deepening of reform and promoting high-quality development. It will better safeguard the people''s demand for cosmetics and inject a strong impetus into the high-quality development of the cosmetics industry. NMPA’s Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development 2025-12-22 To further coordinate high-quality development and high-level safety in the cosmetics sector, and thereby better meet the people''s new expectations for a better life in the new era, the following opinions are proposed to deepen the reform of cosmetics regulation and promote the high-quality development of the cosmetics industry. Policy Interpretation of the NMPA’s Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development 2025-12-22 To thoroughly implement the important instructions of General Secretary Xi Jinping on drug regulation and industrial development, further coordinate high-quality development and high-level safety in the cosmetics sector, and thereby better meet the people''s new expectations for a better life in the new era, the NMPA has issued the NMPA''s Opinions on Deepening the Reform of Cosmetics Regulation and Promoting High-Quality Industry Development (hereinafter referred to as the Opinions). The key points are interpreted as follows. NMPA Notice on Conducting a Pilot Program for Electronic Labeling of Cosmetics GYJZ [2025] No.16 2025-11-28 The National Medical Products Administration (NMPA) has decided to carry out a pilot program for cosmetic electronic labeling in accordance with the Regulations on Supervision and Administration of Cosmetics (hereinafter referred to as the "Regulations"). The relevant matters are hereby notified as follows. Announcement of the National Medical Products Administration (NMPA) on Matters Related to the Administration of the Inventory of Existing Cosmetic Ingredients (IECIC) (No. 61 of 2025) 2025-07-21 To implement the Regulations on Supervision and Administration of Cosmetics, further regulate the administration of cosmetic ingredients, and encourage innovation in raw materials, the following matters concerning the Inventory of Existing Cosmetic Ingredients (hereinafter referred to as the Inventory) are hereby announced. 1 2 3 ... 6 > Policies Interpretation Procedure for Information Sharing Between Regulatory Agencies Policy measures to advance drug, medical device regulation reform Must read for foreign investors in China Newsletter Volume I 2026 Volume VI 2025 2025 Special Issue for Cosmetics Volume V 2025 Volume IV 2025 About NMPA Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News Drugs Medical Devices Cosmetics Resources Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Copyright © National Medical Products Administration All rights reserved. Presented by China Daily. 京ICP备13027807号-2', '{"source_registry_version":"2026-06-25","authority":"National Medical Products Administration","domain":"cosmetics","tags":["cosmetics","china","nmpa","notices"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('cn-nmpa-cosmetics-labeling-measures', 'Measures for the Administration of Cosmetics Labels Announcement', 'https://english.nmpa.gov.cn/2021-06/03/c_655128.htm', 'National Medical Products Administration', 'CN', 'cosmetics', 'notice', 'high', '["cosmetics","labeling","china","nmpa"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('cn-nmpa-cosmetics-labeling-measures', 'a103d8da73b270dac17dbd67bc8bf889efa755e3ae2ed07a22b76537e6d3a7f6', '2026-06-25T09:45:50.145Z', true, 11407, 2177, 'data/knowledge/documents/cn-nmpa-cosmetics-labeling-measures.md', 'NMPA Announcement on Issuance and Implementation of the Measures for the Administration of Cosmetics Labels 中文 | Contact Us | search search nav Home + About NMPA + Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News + Drugs + Medical Devices + Cosmetics + Resources + Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Home > Cosmetics NMPA Announcement on Issuance and Implementation of the Measures for the Administration of Cosmetics Labels CCFDIE | Updated: 2021-06-03 655128 2021-06-03 13:20:22.0 NMPA Announcement on Issuance and Implementation of the Measures for the Administration of Cosmetics Labels Administration of Cosmetics Labels 48 16573 Cosmetics 2@NMPA /enpproperty--> In order to strengthen the supervision and administration of cosmetics labels, standardize the use of cosmetics labels and protect the legitimate rights and interests of consumers, according to the Regulations for the Supervision and Administration of Cosmetics , NMPA has drafted the Measures for the Administration of Cosmetics Labels (hereinafter referred to as the Measures ), which are hereby promulgated. On May 31, matters related to implementation of the Measures are hereby announced as follows: Cosmetics registrants and filing applicants are encouraged to label and mark cosmetics according to the Measure s from the date of promulgation of this Announcement. As of May 1, 2022, cosmetics under application for registration or filing must comply with the Measures; as for the cosmetics for which application or filing has been previously made and labeling and marking fails to comply with the Measures , the cosmetics registrants and filing applicants must complete the update of product labels prior to May 1, 2023, so as to make them comply with the Measures . About NMPA Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News Drugs Medical Devices Cosmetics Resources Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Copyright © National Medical Products Administration All rights reserved. Presented by China Daily. 京ICP备13027807号-2', '{"source_registry_version":"2026-06-25","authority":"National Medical Products Administration","domain":"cosmetics","tags":["cosmetics","labeling","china","nmpa"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('cn-nmpa-cosmetics-registration-filing', 'The Provisions for Registration and Filing of Cosmetics', 'https://english.nmpa.gov.cn/2022-06/30/c_785637.htm', 'National Medical Products Administration', 'CN', 'cosmetics', 'regulation', 'high', '["cosmetics","registration","filing","ingredients"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('cn-nmpa-cosmetics-registration-filing', '72490df542a56ec53a5af52df4224c44b5db297cb7f1ec81ec558626487a8224', '2026-06-25T09:45:50.145Z', true, 20147, 7703, 'data/knowledge/documents/cn-nmpa-cosmetics-registration-filing.md', 'The Provisions for Registration and Filing of Cosmetics 中文 | Contact Us | search search nav Home + About NMPA + Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News + Drugs + Medical Devices + Cosmetics + Resources + Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Home > Laws and Regulations The Provisions for Registration and Filing of Cosmetics Updated: 2022-06-30 785637 2022-06-30 21:52:37.0 The Provisions for Registration and Filing of Cosmetics 48 16576 Laws and Regulations 2@NMPA /enpproperty--> The Provisions for Registration and Filing of Cosmetics Order of the State Administration for Market Regulation No. 35 The Provisions for Registration and Filing of Cosmetics adopted at the 14th Executive Meeting of the State Administration for Market Regulation on December 31, 2020 is hereby promulgated and shall go into effect as of May 1, 2021. Minister Zhang Gong January 7, 2021 The Provisions for Registration and Filing of Cosmetics (Announced by Order No. 35 of the State Administration for Market Regulation on January 7, 2021) Chapter I General Provisions Article 1 These Provisions are formulated for the purpose of regulating registration and filing of cosmetics, while ensuring the quality and safety of cosmetics in accordance with the Regulations on Supervision and Administration of Cosmetics . Article 2 The registration and filing activities of cosmetics and new cosmetic ingredients and their supervision and administration within the territory of the People''s Republic of China shall comply with these Provisions. Article 3 The registration of cosmetics and new cosmetic ingredients refers to the activity that a registrant submits a registration application in accordance with legal procedures and requirements, and the drug regulatory department reviews the safety and quality control of the cosmetics and new cosmetic ingredients applied for registration and decides whether it agrees to the application. The filing of cosmetics and new cosmetic ingredients refers to the activity that a filing person submits the dossier indicating the safety and quality control of the cosmetics and new cosmetic ingredients in accordance with legal procedures and requirements, and the drug regulatory department files the submitted dossier for reference. Article 4 The State implements registration administration for special cosmetics and new cosmetic ingredients with high risks, and filing administration for general cosmetics and other new cosmetic ingredients. Article 5 The National Medical Products Administration (NMPA) is responsible for the registration and filing administration of special cosmetics, imported general cosmetics and new cosmetic ingredients, and guiding and supervising the related cosmetic filing work undertaken by the drug regulatory departments of provinces, autonomous regions, and municipalities. The NMPA may entrust the drug regulatory departments of provinces, autonomous regions, and municipalities directly under the Central Government that have corresponding capabilities to implement the filing administration of imported general cosmetics. The cosmetic technical assessment agency of the NMPA (hereinafter referred to as the technical assessment agency) is responsible for the technical assessment of the registration of special cosmetics and new cosmetic ingredients, the technical verification of imported general cosmetics and the new cosmetic ingredients after filing, and the evaluation of the use and safety reports of new cosmetic ingredients. The administrative affairs service agency of the NMPA (hereinafter referred to as service agency), the inspection agency, adverse reaction monitoring agency and information management agency shall be responsible for the registration acceptance, on-site inspections, adverse reaction monitoring, informatization and management respectively. Article 6 The drug regulatory departments of provinces, autonomous regions and municipalities are responsible for the filing administration of domestic general cosmetics within their administrative areas, implementing the filing administration of imported general cosmetics in the name of the NMPA within the scope of entrustment, and assisting in the on-site inspection for registration of special cosmetics etc. Article 7 The registrant and filing person of cosmetics and new cosmetic ingredients shall perform product registration and filing obligations in accordance with law and shall be responsible for the quality and safety of cosmetics and new cosmetic ingredients. Registrants and filing persons of cosmetics and new cosmetic ingredients shall comply with the requirements of relevant laws, administrative regulations, mandatory national standards and technical specifications when applying for registration or filing for filing, and shall be responsible for the authenticity and scientificalness of the submitted dossiers. Article 8 Overseas registrants and filing persons shall designate an enterprise legal person within the territory of China as the domestic responsible person. The domestic responsible person shall fulfill the following obligations: (1) In the name of the registrants and filing persons, handling the registration and filing of cosmetics and new cosmetic ingredients; (2) Assisting the registrants and filing persons in carrying out cosmetic adverse reaction monitoring, safety monitoring and reporting of new cosmetic ingredients; (3) Assisting the registrants and filing persons in implementing the recall of cosmetics and new cosmetic ingredients; (4) In accordance with the agreement with the registrants and filing persons, assuming corresponding quality and safety responsibilities for cosmetics and new cosmetic ingredients released in the domestic market; and (5) Cooperating with the supervision and inspection of the drug regulatory department. Article 9 The drug regulatory department under the State Council shall release the information on registration and filing of cosmetics and new cosmetic ingredients to the public for reference within 5 working days since the date when the registration is approved or the filing is filed. Article 10 The NMPA shall strengthen informatization to provide convenient services for registrants and filing persons. Registrants and filing persons of cosmetics and new cosmetic ingredients shall apply for registration and filing through the information service platform of registration and filing for cosmetics and new cosmetic ingredients (hereinafter referred to as the information service platform) in accordance with regulations. The NMPA shall formulate the inventory of existing cosmetic ingredients, update it in a timely manner and make it public to facilitate enterprises for reference. Article 11 The drug regulatory department may establish an expert consultation mechanism to listen to expert opinions on important issues in the process of technical evaluation, on-site inspection, supervision and inspection, and give play to the role of experts for technical support. 1 2 3 ... 5 > Policies Interpretation Policy measures to advance drug, medical device regulation reform Must read for foreign investors in China 2025 Share your views on business environment in China Newsletter Volume I 2026 Volume VI 2025 2025 Special Issue for Cosmetics About NMPA Leadership Our Responsibilities NMPA Organizations Affiliated Institutions Contact Us News Drugs Medical Devices Cosmetics Resources Database Worldwide Pharmacopoeia Newsletter Policies Interpretation Popular Science Copyright © National Medical Products Administration All rights reserved. Presented by China Daily. 京ICP备13027807号-2', '{"source_registry_version":"2026-06-25","authority":"National Medical Products Administration","domain":"cosmetics","tags":["cosmetics","registration","filing","ingredients"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('cn-customs-import-export-tariff-regulations', 'China customs duties and declaration service guide', 'https://english.www.gov.cn/services/visitchina/202008/04/content_WS5f2905dec6d029c1c26372f0.html', 'The State Council of the People''s Republic of China', 'CN', 'customs', 'government_guide', 'high', '["customs","import","export","tariff"]'::jsonb, 30, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('cn-customs-import-export-tariff-regulations', '96559e7b15d8e78ba5037a5f8609618106fe263fe278fad892dc497dfcae8490', '2026-06-25T09:45:50.145Z', true, 33413, 18700, 'data/knowledge/documents/cn-customs-import-export-tariff-regulations.md', 'Customs App HOME NEWS INSTITUTIONS POLICIES ARCHIVE 中文 HOME NEWS INSTITUTIONS POLICIES ARCHIVE 中文 Customs Updated: August 4, 2020 14:53 english.www.gov.cn 1. Customs clearance concerning inbound and outbound passengers Customs clearance refers to customs procedures involving inbound and outbound passengers declaring their baggage to the customs authorities, who check items and may require the payment of a duty — or exempt them from duty — in accordance with the law. 2. Which documents do inbound & outbound travelers need to provide when declaring at Customs? Travelers who declare items at customs should submit a Declaration Form of In/Outbound Passenger Luggage at the Customs of the People’s Republic of China or other declaration documents, valid inbound or outbound certificates — and other documents issued by authorized organs of the People’s Republic of China, such as inbound and outbound permits for the mailed items and business documents. 3. What happens when foreign nationals fail to declare items as required by China’s customs authorities? Travelers who fail to declare items to the customs authorities — and bring in prohibited/restricted, or taxable goods or articles — are penalized in accordance with the Customs Law of the People’s Republic of China and Regulation of the People’s Republic of China on the Implementation of Customs Administrative Punishment. 4. Details about the "Goods to Declare" and "Nothing to Declare" clearance system The dual Customs clearance system — "Goods to Declare" and "Nothing to Declare" — is a procedure to deal with items belonging to inbound and outbound passengers — and this system is used in many countries. It involves two channels, the Red Channel "Goods to Declare," and the Green Channel "Nothing to Declare" — in both English and Chinese. Most of the customs authorities in China use this clearance system. 5. Which channel should I choose when entering or leaving China? In ports that have a dual customs clearance system: Travelers who carry articles that should be declared should choose the Red Channel "Goods to Declare"; passengers who do not know which channel to choose should also choose this channel; other passengers can choose the Green Channel "Nothing to Declare." 6. What are the customs procedures for mailed items entering China? Local post offices handle the customs procedures on behalf of recipients of mailed items entering China in different cities. The post offices deliver the mailed items — after they are checked by the customs authorities. The recipient can also go to the post office to handle customs formalities in person — in special circumstances, or at his/her own request. 7. What are the customs procedures for mailing items from China? The sender should fill in a customs declaration form before mailing items from China. In the case of a parcel, the sender should also fill in a green customs inspection tag — including a description of the contents, quantity and value. The sender should then proceed to the customs counter in the post office — and, once the parcel is cleared, he/she can leave it at the post office. In post offices where there are no customs counters, the sender can mail his/her parcel, following the procedures above — and the post office is responsible for sending the parcel to the customs authorities before it is then sent overseas. 8. Is there any duty-free policy for mailed items entering China? Personal mailed items entering China are subject to customs import duties in accordance with the law. However, items with import duties not exceeding 50 yuan are exempt from import duties. 9. What is the maximum value of mailed items? Items sent to or from Hong Kong, Macao, and Taiwan: the maximum value is 800 yuan. Items sent to or from foreign countries: the legal maximum value is 1,000 yuan. 10. Regulations regarding inbound & outbound personal mailed items Inbound and outbound personal mailed items are items for personal use, and of a reasonable quantity for such items. The main goals of the customs authorities concerning such items involve ensuring normal exchange, covering reasonable personal needs, and limiting smuggling. The customs authorities set up maximum value, and duty-exemption value of mailed items, as well as list of items prohibited and restricted from mailing. The customs authorities check items and may require the payment of a duty — or exempt them from duty — in accordance with the law. 11. Customs regulation on personal postal articles Personal postal articles refer to inward/outward passenger baggage, gifts exchanged between relatives and friends and other personal articles, limited to reasonable quantities for personal use. Inward/outward personal postal articles shall be limited to reasonable quantities for personal use. The customs supervision principles for inward/outward personal postal articles are: expedite regular travel and take consideration of personal reasonable use, and restrict smuggling and other illegal activities. Based on the principles, the Customs promulgated the quantity limit of articles and prohibited and restricted articles delivered by mail. The Customs will inspect articles and levy or waive duties according to regulations. 1) The Customs shall impose import duty on personal articles mailed from other areas and waive duties for articles with import duties not more than 50 yuan. 2) Personal articles mailed from or to Hong Kong, Macao and Taiwan shall be limited to the value of 800 yuan, and 1,000 yuan for personal articles mailed from or to other countries and regions. 3) Personal articles whose value exceeds the above-mentioned duty-free limit should be returned or be cleared from customs according to goods regulations. Nonetheless, if the mail contains only one inseparable article whose value exceeds the limit, the mail will be cleared as personal article upon verification by the customs as article for personal use. 4) Inward/outward commercial mails should be cleared in line with goods regulation. 12. Articles prohibited as imports: 1) Arms, ammunition and explosives, of all kinds. 2) Coins, banknotes, currency notes, securities of any kind payable to bearer, travelers’ checks, counterfeit currencies and counterfeit negotiable securities. 3) Printed matter, films, photographs, gramophone records, cinematographic films, loaded recording tapes and videotapes, compact discs (video and audio), storage medium for the computer and other articles which are detrimental to the political, economic, cultural and moral interests of the People’s Republic of China. 4) Deadly poisons of all kinds. 5) Opium, morphine, heroin, marijuana and other addiction-inducing drugs and psychedelic substances. 6) Animals, plants and products thereof infected with or carrying disease germs, insect pests and other harmful organisms. 7) Foodstuff, medicines and other articles coming from epidemic-stricken areas and harmful to man and livestock or those capable of spreading diseases. 13. Articles prohibited as exports: 1) All articles listed as articles prohibited as imports. 2) Manuscripts, printed matter, films, photographs, gramophone records, cinematographic films, loaded recording tapes, videotapes, compact discs (video and audio), storage medium for the computer and other articles which involve State secrets. 3) Valuable cultural relics and other relics prohibited as exports. 4) Endangered and rare animals and plants (including specimens thereof) and their seeds or reproducing materials. 14. Articles subject to restrictions as imports: 1) Radio transmitter-receivers and units ensuring secrecy in communication. 2) Tobacco and wines. 3) Endangered and rare animals and plants (including specimens thereof) and their seeds or reproducing materials. 4) Renminbi (national currency). 5) Other articles restricted from importation by Customs. 15. Articles subject to restrictions as exports: 1) Precious metals such as gold and silver and articles made thereof. 2) Renmin', '{"source_registry_version":"2026-06-25","authority":"The State Council of the People''s Republic of China","domain":"customs","tags":["customs","import","export","tariff"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
