insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('cn-mofcom-export-control-portal', 'ce3513756ae131dc62241838ed2b43b1e21b3a565011857721156b550ab4fc6e', '2026-06-25T09:45:50.145Z', true, 24907, 1798, 'data/knowledge/documents/cn-mofcom-export-control-portal.md', '中国出口管制信息网 网站导航 网站首页 国内动态 国际动态 合规服务 政策法规 常见问题 各方观点 两用物项查询 快速了解出口管制 在线办事 相关链接 在线办事 两用物项和技术进出口审批 最终用户和最终用途说明 相关链接 外交部 工业和信息化部 海关总署 国家国防科技工业局 中国出口管制信息网 CHINA EXPORT CONTROL INFORMATION 首 页 国内动态 国际动态 合规服务 政策法规 常见问题 各方观点 快速了解出口管制 两用物项出口管制清单数据库 在线办事 两用物项和技术进出口审批 最终用户和最终用途说明 相关链接 外交部 工业和信息化部 海关总署 国家国防科技工业局 国内动态 商务部新闻发言人就进一步完善战略矿产两用物项出口管制违法违规行为举报处理工作答记者问 中韩出口管制对话机制第三次会议及政企交流活动在陕西西安举行 中英出口管制工作组第二次会议在英国伦敦举行 商务部：坚决反对欧盟第20轮对俄制裁列单中国企业 商务部新闻发言人就美众议院外交事务委员会通过MATCH等法案答记者问 商务部新闻发言人就将7家欧盟实体列入出口管制管控名单答记者问 商务部回应稀土出口管制：中美将通过经贸磋商机制保持沟通 2025年全国出口管制工作会议在京召开 商务部国际贸易谈判代表兼副部长王受文在京出席2024年出口管制合规大会 2024年全国出口管制工作会议在京召开 中国首次发布出口管制的白皮书 国际动态 芬兰即将修订《两用物项出口管制法》 2026-05-29 德国中国商会就欧委会依据《外国补贴条例》排除中企发表声明 2026-05-03 日本通过内阁决议正式允许出口杀伤性武器 2026-04-21 美国国务院就通用电气航空航天公司违反出口法规一事达成3600万美元和解协议 2026-04-18 芬兰：就两项新的两用物项出口国家通用许可 启动意见征询 2026-04-17 泰国收紧原棕榈油出口管制 2026-04-17 加拿大更新出口管制清单指南 2026-04-17 合规服务 培训资料 培训计划 --> 合规案例 合规案例（五）：某公司出口管制合规工作实践经验 2026-05-29 某企业无证出口军用战术背心案 2026-05-11 某企业将钨粉混藏于普通货物进行违规出口案 2026-04-17 某企业违规出口亚硫酰氯的锂电池案 2026-03-13 某企业擅自出口涉及军工或高技术含量材料案 2026-02-12 出口管制合规对话系列（二） 2026-01-30 出口管制合规对话系列（一） 2026-01-30 政策法规 国内 国际 中华人民共和国两用物项出口管制条例 2024-10-23 中华人民共和国出口管制法 2021-12-30 中华人民共和国核安全法 2021-12-30 中华人民共和国生物安全法 2021-12-30 中华人民共和国密码法 2021-12-30 常见问题 两用物项常见问题解答之五（稀土相关物项） 2026-01-26 两用物项常见问题解答之四（稀土） 2025-04-25 两用物项常见问题解答之三（参考海关商品编号等问题） 2025-04-08 两用物项出口许可申请填报指南 2025-03-29 两用物项常见问题解答之二（钨、碲） 2025-03-12 各方观点 英伟达CEO：美国对华H20芯片禁令&ldquo;令人深感痛苦&rdquo;，限制措施是短视行为 2025-05-23 对稀土相关物项加强出口管制体现维护国家安全的决心 2025-04-11 美科技巨头喊话特朗普政府放宽对华芯片出口管制，专家解读 2025-03-11 欧盟对美国限制人工智能芯片出口表达担忧 2025-01-17 出台两用物项出口管制条例是完善涉外法治体系建设的重大举措 2024-10-19 《中华人民共和国出口管制法》解读（一） 快速了解我国出口管制 如何建立有效的出口管制内部合规机制 网站声明 关于我们 主办单位：中华人民共和国商务部 网站管理： 商务部电子商务和信息化司 技术支持：北京国富信数字技术发展有限公司 技术支持电话：010-67801943 邮箱：zhouxiaohui@mofcom.gov.cn 京公网安备 11040102700091号 京ICP备05004093号-1 网站标识码bm22000001', '{"source_registry_version":"2026-06-25","authority":"Ministry of Commerce of the People''s Republic of China","domain":"export_control","tags":["export-control","dual-use","mofcom","china"],"format":"html","page_count":null,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('asean-cosmetic-directive', 'ASEAN Cosmetic Directive', 'https://aseancosmetics.org/docdocs/directive.pdf', 'ASEAN Cosmetics Association / ASEAN Cosmetic Documents', 'ASEAN', 'cosmetics', 'directive', 'high', '["asean","cosmetics","directive","labeling"]'::jsonb, 90, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('asean-cosmetic-directive', '0089f5bdba0d75d3a2eacb8064c636398c761dbcc2f32acff6e4386bed826dcf', '2026-06-25T09:45:50.145Z', true, 30797, 15458, 'data/knowledge/documents/asean-cosmetic-directive.md', '________________________________________________ SCHEDULE B ASEAN COSMETIC DIRECTIVE ______________________________ Schedule B – ASEAN Cosmetic Directive SCHEDULE B ASEAN COSMETIC DIRECTIVE The Governments of Brunei Darussalam, the Kingdom of Cambodia, the Republic of Indonesia, the Lao People''s Democratic Republic, Malaysia, the Union of Myanmar, the Republic of the Philippines, the Republic of Singapore, the Kingdom of Thailand and the Socialist Republic of Vietnam, Member States of the Association of Southeast Asian Nations (hereinafter referred to as "ASEAN"); HAVING regard to the Principles of Harmonization of Cosmetic Regulations, the Common Technical Documents for Cosmetics and the progress made in its implementation; and DESIRING to implement the Agreement on the ASEAN Harmonized Cosmetic Regulatory Scheme signed on the ______ of September 2003. HAVE ADOPTED THIS DIRECTIVE: ARTICLE 1 General Provisions 1. Member States shall undertake all necessary measures to ensure that only cosmetic products which conform to the provisions of this Directive, its Annexes and Appendices may be placed in the market. 2. Notwithstanding to Article 4 and without prejudice to Article 5 and Article 11, a Member State may not, for reasons related to the requirements laid down in this Directive, its Annexes and Appendices, refuse, prohibit or restrict the marketing of any cosmetic products which comply with the requirements of this Directive, its Annexes and Appendices thereto. 3. The company or person responsible for placing the cosmetic products in the market, shall notify the regulatory authority responsible for cosmetics (hereafter referred to as regulatory authority) of each Member State where the product will be marketed of the place of the manufacture or of initial importation before the product is placed in the market. 4. The company or person responsible for placing the cosmetic products in the market shall for control purposes keep the product’s technical and safety information readily accessible to the regulatory authority of the Member State concerned. Schedule B – ASEAN Cosmetic Directive ARTICLE 2 Definition and Scope of Cosmetic Product 1. A “cosmetic product” shall mean any substance or preparation intended to be placed in contact with the various external parts of the human body (epidermis, hair system, nails, lips and external genital organs) or with the teeth and the mucous membranes of the oral cavity with a view exclusively or mainly to cleaning them, perfuming them, changing their appearance and/or correcting body odours and/or protecting them or keeping them in good condition. 2. The products to be considered as cosmetic products within the meaning of this definition are listed in Appendix I. 3. Cosmetic products containing any substances in Annex V shall be excluded from the scope of this Directive. Member States may take measures as they deem necessary with regard to those products. ARTICLE 3 Safety Requirements 1. A cosmetic product placed on the market must not cause damage to human health when applied under normal or reasonably foreseeable conditions of use, taking account, in particular, of the product’s presentation, its labeling, instructions for its use and disposal, warning statements as well as any other indication or information provided by the manufacturer or his authorized agent or by any other person responsible for placing the product on the market. 2. The provision of such warnings shall not, in any event, exempt any person from compliance with the other requirements laid down in this Directive. ARTICLE 4 Ingredient Listings 1. Member States shall adopt the Cosmetic Ingredient Listings of the EU Cosmetic Directive 76/768/EEC including the latest amendments. 2. Member States shall prohibit the marketing of cosmetic products containing: a) substances listed in Annex II; b) substances listed in the first part of Annex III, beyond the limits and outside the conditions laid down; c) colouring agents other than those listed in Annex IV, Part 1 with the exception of cosmetic products containing colouring agents intended solely to colour hair; Schedule B – ASEAN Cosmetic Directive d) colouring agents listed in Annex IV, Part 1 used outside the conditions laid down, with the exception of cosmetic products containing colouring agents intended solely to colour hair; e) preservatives other than those listed in Annex VI, Part 1; f) preservatives listed in Annex VI, Part 1 beyond the limits and outside the conditions laid down therein, unless other concentrations are used for specific purposes apparent from the presentation of the product; g) UV filters other than those listed in Annex VII, Part 1; and h) UV filters listed in Annex VII, Part 1 beyond the limits and outside the conditions laid down therein. 3. The presence of traces of the substances listed in Annex II shall be allowed provided that such presence is technically unavoidable in good manufacturing practice and that it conforms with Article 3. 4. Member States shall allow the marketing of cosmetic products containing: a) the substances and other ingredients listed in Annex III, Part 2 within the limits and under the conditions laid down, up to the dates in column(g) of that Annex; b) the colouring agents listed in Annex IV, Part 2, used within the limits and under the conditions laid down, until the admission dates given in that Annex; c) the preservatives listed in Annex VI, Part 2, within the limits and under the conditions laid down, until the dates given in column (f) of that Annex. However, some of these substances may be used in other concentrations for specific purposes apparent from the presentation of the product; d) the UV filters listed in Part 2 of Annex VII, within the limits and under the conditions laid down, until the dates given in column (f) of that Annex. At these dates, these substances, colouring agents, preservatives and UV filters shall be: - definitively allowed, or - definitively prohibited (Annex II), or - maintained for a given period specified in Part 2 of Annexes III, IV and VII, or - deleted from all the Annexes, on the basis of available scientific information or because they are no longer used. Schedule B – ASEAN Cosmetic Directive ARTICLE 5 ASEAN Handbook of Cosmetic Ingredients 1. Notwithstanding the Article 4, a Member State may authorize the use within its territory of other substances, not contained in the lists of substances allowed, for certain cosmetic products specified in its national authorization, subject to the following conditions: a) the authorization must be limited to a maximum of three years; b) the Member State must carry out an official check on cosmetic products manufactured from the substance or preparation use of which it has authorized; c) cosmetic products thus manufactured must bear a distinctive indication which will be defined in the authorization. 2. The Member State shall forward to the ASEAN Secretariat and to the other Member States the text of any authorization decision taken pursuant to paragraph 1 within two months of the date on which it came into effect. 3. Before expiry of the three-year period provided for in paragraph 1, the Member State may submit to the ACC a request for the inclusion in the list of permitted substances (Annex VIII – the ASEAN Handbook of Cosmetic Ingredients) given national authorization in accordance with paragraph 1. At the same time, it shall supply supporting documents setting out the grounds on which it deems such inclusion justified and shall indicate the uses for which the substance or preparation is intended. A decision shall be taken on the basis of the latest scientific and technical knowledge, after consultation, at the initiative of the ACC or of a Member State, as to whether the substance in question may be included in a list of permitted substances (Annex VIII – the ASEAN Handbook of Cosmetic Ingredients) or whether the national authorization should be revoked. Notwithstan', '{"source_registry_version":"2026-06-25","authority":"ASEAN Cosmetics Association / ASEAN Cosmetic Documents","domain":"cosmetics","tags":["asean","cosmetics","directive","labeling"],"format":"pdf","page_count":8,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('asean-cosmetic-labeling-requirements', 'Appendix II ASEAN Cosmetic Labeling Requirements', 'https://asean.org/wp-content/uploads/2012/05/Appendix-II-ASEAN-Cosmetic-Labeling-Requirements.pdf', 'ASEAN', 'ASEAN', 'cosmetics', 'guideline', 'high', '["asean","cosmetic-labeling","mandatory-label-items"]'::jsonb, 90, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('asean-cosmetic-labeling-requirements', 'd48fe6280f1fbd089f017a1ca1c2044fd1962c25bf34d6bfd6e0f5ecbdd0bc10', '2026-06-25T09:45:50.145Z', true, 22976, 5247, 'data/knowledge/documents/asean-cosmetic-labeling-requirements.md', '4 September 2007 APPENDIX II ASEAN COSMETIC LABELING REQUIREMENTS A. OBJECTIVE 1. This document provides guidance for the labeling requirements of cosmetic products to which Article 6 of the ASEAN Cosmetic Directive 05/01/ACCSQPWG apply. B. SCOPE AND DEFINITIONS 1. For the purpose of this document: Name of the cosmetic product means the name given to a cosmetic product, which may be an invented name, together with a trade mark or the name of the manufacturer; Immediate packaging means the container or other form of packaging immediately in contact with the cosmetic product; Outer packaging means the packaging into which is placed the immediate packaging; Labeling means information written or printed or graphic matter on the immediate or outer packaging and any form of leaflets; C. LABELING OF COSMETIC PRODUCTS 1. The following particulars shall appear on the outer packaging of cosmetic products or, where there is no outer packaging, on the immediate packaging of cosmetic products: a) The name of the cosmetic product and its function, unless it is clear from the presentation of the product; b) Instructions on the use of the cosmetic product, unless it is clear from the product name or presentation; c) Full ingredient listing. The ingredients must be declared in descending order of weight at the time they are added. Perfume 4 September 2007 and aromatic compositions and their raw materials may be referred to by the word “perfume”, “fragrance”, “aroma” or “flavor”. Ingredients in concentrations of less than 1% may be listed in any order after those of concentration of more than 1%. Coloring agents may be listed in any order after the other ingredients, in accordance with the color index number or denomination adopted in Annex IV. For decorative cosmetic products marketed in several color shades, all coloring agents used in the range may be listed, provided that the terms “may contain” or “+/-“ be added. The ingredients shall be specified using the nomenclature from the latest edition of standard references (Refer to appendix A). Botanicals and extract of botanicals should be identified by its genus and species. The genus may be abbreviated; The following shall not, however, be regarded as ingredients: • Impurities in the raw materials used; • Subsidiary technical materials used in the preparation but not present in the final products; • Materials used in strictly necessary quantities as solvents, or as carriers, for perfume and aromatic compositions; d) Country of manufacture; e) The name and address of the company or person responsible for placing the product on the local market; f) The contents given by weight or volume, in either metric or both metric and imperial system; g) The manufacturer’s batch number; h) The manufacturing or the expiry date of the product in clear terms (e.g. month/year). The date shall be clearly expressed and shall consist either of the month and year or the day, month and year in that order. The date of minimum durability shall be the date until which this product, stored under appropriate conditions, continues to fulfil its initial function and, in particular, remains in conformity with article 3. It should be preceded by the words “expiry date” or “best before”. If necessary, this information shall be supplemented by an indication of the conditions which must be satisfied to guarantee the stated durability. 4 September 2007 Indication of the expiry date shall be mandatory for cosmetic products the minimum durability of which is less than 30 months. i) Special precautions to be observed in use, especially those listed in the column “Conditions of use and warnings which must be printed on the label in Annexes __”, which must appear on the label as well as any special precautionary information on the cosmetic products. Member countries may require specific warnings based on local needs for declaration of ingredients from animal origin. In this case: i. There must be a statement (of any format) on the product label signaling the presence of ingredients of animal origin; ii. For ingredients of bovine or porcine origin, the exact animal must be declared; 2. In cases where the size, shape or nature of the container or package does not permit the particulars laid down in paragraphs 1 (a) – (i) to be displayed, the use of leaflets, pamphlets, hang tags, display panel, shrink wrap, etc. shall be allowed. However the following particulars at least shall appear on small immediate packaging: a) The name of the cosmetic product; b) The manufacturer’s batch number; 3. The particulars referred to in paragraphs 1 and 2 shall be easily legible, clearly comprehensible and indelible; 4. The particulars listed in paragraph 1 shall appear in English and/or National Language and/or a language understood by the consumer where the product is marketed. Member Countries may require that the information in paragraphs a), b), e), f) and i) be in the national language or a language easily understood by the consumer; APPENDIX A List of Standard References to be used for Cosmetic Ingredient Nomenclature 4 September 2007 1. International Cosmetic Ingredient Dictionary; 2. British Pharmacopeia; 3. United States Pharmacopeia; 4. Chemical Abstract Services;', '{"source_registry_version":"2026-06-25","authority":"ASEAN","domain":"cosmetics","tags":["asean","cosmetic-labeling","mandatory-label-items"],"format":"pdf","page_count":4,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
insert into public.knowledge_sources (source_key, title, source_url, authority, jurisdiction, domain, source_type, priority, tags, cache_days, is_active) values ('asean-cosmetic-claims-guideline', 'Appendix III ASEAN Cosmetic Claim Guideline', 'https://asean.org/wp-content/uploads/2012/05/Appendix-III-ASEAN-Cosmetic-Claim-Guideline.pdf', 'ASEAN', 'ASEAN', 'cosmetics', 'guideline', 'medium', '["asean","cosmetic-claims","product-classification"]'::jsonb, 90, true) on conflict (source_key) do update set title = excluded.title, source_url = excluded.source_url, authority = excluded.authority, jurisdiction = excluded.jurisdiction, domain = excluded.domain, source_type = excluded.source_type, priority = excluded.priority, tags = excluded.tags, cache_days = excluded.cache_days, is_active = true;
insert into public.knowledge_snapshots (source_key, content_hash, fetched_at, from_cache, bytes, text_chars, document_path, extract, metadata) values ('asean-cosmetic-claims-guideline', '28ec4751225fef11208c3cc9166e71bf1ca5bcde58a14be680e2f448e6f4533b', '2026-06-25T09:45:50.145Z', true, 101269, 7558, 'data/knowledge/documents/asean-cosmetic-claims-guideline.md', 'ASEAN Cosmetic Documents Appendix III – ASEAN Cosmetic Claims Guidelines Version Date 04 September 2007 Page 1 APPENDIX III – ASEAN COSMETIC CLAIM GUIDELINE 1. Introduction The evaluation of product claims cannot be separated from the consideration of whether a product is a cosmetic or not. Whether a product can be considered to be a cosmetic product depends on several factors, claims are an important element of this process. This guideline provides a simple 5-step decision-making process that helps to identify products and claims which can be considered to be cosmetics. The document also provides some examples of unacceptable claims for cosmetic products. However, it is not to be taken as the final authority nor as an exhaustive list. 2. Decision Process to identify cosmetic products and allowable claims (See summary chart below) a. Composition of cosmetics The product should contain only ingredients that comply with the annexes of ACD, and does not contain any ingredients that are banned in the ACD. b. Target site of application of cosmetics The product should be intended to be placed in contact with the various external parts of the human body (epidermis, hair system, nails, lips and external genital organs) or with the teeth and the mucous membranes of the oral cavity. Products that are intended to be ingested, injected or placed in contact with other parts of the human body e.g. the mucous membranes of the nasal passage or the internal genitalia cannot be considered to be cosmetic products. c. Intended main function of cosmetics The product should be applied to the permitted parts of the human body with a view exclusively or mainly to clean them, perfuming them, changing their appearance and/or correcting body odors and/or protecting them or keeping them in good condition. Note that products may have a secondary, minor function that is outside the above scope. Some examples of acceptable secondary claim areas are given below. Note that this is not an exhaustive list. ● Dandruff ● Caries ● Cellulite ● Hair loss ● Bust contouring ● Acne ● Anti-bacterial ● Mouth wash d. Product presentation of cosmetics The product should not be presented as treating or preventing disease in human beings. The following features of the product should be taken into account i. Product claims and the context in which the claims are made ii. Labeling and packaging/packaging inserts (including graphics) ASEAN Cosmetic Documents Appendix III – ASEAN Cosmetic Claims Guidelines Version Date 04 September 2007 Page 2 iii. Promotional literature, including testimonials and literature issued by third parties on behalf of the supplier iv. Advertisements v. The product form and the way it is to be used e.g. capsule, tablet, injection etc. vi. Particular target of the marketing information e.g. specific population groups with, or particularly vulnerable to, specific diseases of adverse conditions. e. Physiological effects of cosmetics Every product that has an effect on the functioning of the body also has an effect on its metabolism. Cosmetic products typically have effects that are not permanent, and have to be used regularly to maintain their effects. As a first point of guidance, claims that can be reasonably expected for product types given in the Illustrative List of Cosmetic Products (Annexe 1 ACD) can be considered to be cosmetic in nature. Section 3. below gives some examples of unacceptable claims for cosmetic products. Note that it is not an exhaustive list. 3. Some examples of unacceptable claims commonly observed for cosmetics under the product types. Product Type Unacceptable claims Hair care products • Eliminates dandruff permanently • Restores hair cells • Hair loss can be arrested or reversed • Stimulates hair growth Depilatories • Stops/retards/prevents hair growth Nail products • Reference to growth resulting from nourishment Skin products • Prevents, reduces or reverses the physiological changes and degeneration conditions brought about by aging • Removes scars • Numbing effect • Prevents, heals, treats or stops acne • Treatment of cellulite • Lose centimetres • Reduces/controls swelling/oedema • Removes/burns fat • Fungicidal action • Virucidal action Oral or dental hygiene products • Treatment or prevention of dental abscess, gumboils, inflammation, mouth ulcers, periodontitis, pyorrhoea, periodontal disease, stomatitis, thrush or any oral diseases or infections ASEAN Cosmetic Documents Appendix III – ASEAN Cosmetic Claims Guidelines Version Date 04 September 2007 Page 3 • Whitens tetracycline-induced stains Deodorants & Anti-perspirants • Completely prevents sweating/perspiration Perfumes/fragrances/colognes • Aphrodisiac or hormonal attraction Note that claims can be softened i.e. made less functional and more cosmetic in nature by the use of modifiers. An example of this would be a claim for removing all oil from skin. This claim could be softened as follows, • Helps to remove oil from skin • Reduces the shine of oily skin • Suitable for oily skin types • Makes your skin feel less oily ASEAN Cosmetic Documents Appendix III – ASEAN Cosmetic Claims Guidelines Version Date 04 September 2007 Page 4 Product Proposition Cosmetic Product 1. Does the product contain only ingredients permitted by the ACD and no ingredients banned by the ACD ? 5. Does the product permanently restore, correct or modify physiological function by exerting a pharmacological, immunological or metabolic action ? 4. Is the product presented as treating or preventing disease in human beings ? 3. Is the product intended exclusively or mainly to clean, perfume, change the appearance and/or correct body odours and/or protect or keep the defined parts of the human body in good condition ? 2. Is the product intended for contact with the various external parts of the human body (epidermis, hair system, nails, lips and external genital organs) or with the teeth and the mucous membranes of the oral cavity ? Decision process to identify cosmetic products & claims Product Proposition 1. Composition 2. Target Site 3. Main Function 4. Non-Cosmetic Presentation 5. Non-Cosmetic Function Cosmetic Product Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic YES YES YES YES YES NO NO NO NO NO Product Proposition Cosmetic Product Product Proposition Cosmetic Product 1. Does the product contain only ingredients permitted by the ACD and no ingredients banned by the ACD ? 5. Does the product permanently restore, correct or modify physiological function by exerting a pharmacological, immunological or metabolic action ? 4. Is the product presented as treating or preventing disease in human beings ? 3. Is the product intended exclusively or mainly to clean, perfume, change the appearance and/or correct body odours and/or protect or keep the defined parts of the human body in good condition ? 2. Is the product intended for contact with the various external parts of the human body (epidermis, hair system, nails, lips and external genital organs) or with the teeth and the mucous membranes of the oral cavity ? Decision process to identify cosmetic products & claims Product Proposition 1. Composition 2. Target Site 3. Main Function 4. Non-Cosmetic Presentation 5. Non-Cosmetic Function Cosmetic Product Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic Not Cosmetic YES YES YES YES YES NO NO NO NO NO ASEAN Cosmetic Documents Appendix III – ASEAN Cosmetic Claims Guidelines Version Date 04 September 2007 Page 5', '{"source_registry_version":"2026-06-25","authority":"ASEAN","domain":"cosmetics","tags":["asean","cosmetic-claims","product-classification"],"format":"pdf","page_count":5,"parse_error":null}'::jsonb) on conflict (source_key, content_hash) do update set fetched_at = excluded.fetched_at, from_cache = excluded.from_cache, bytes = excluded.bytes, text_chars = excluded.text_chars, document_path = excluded.document_path, extract = excluded.extract, metadata = excluded.metadata;
